import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

const REQUIRED_HEADER = "x-custom-auth";
const REQUIRED_VALUE = "my-secret-token";

export default async function (
  request: ZuploRequest,
  context: ZuploContext,
  _options: unknown,
  _policyName: string,
) {
  const headerValue = request.headers.get(REQUIRED_HEADER);

  if (headerValue !== REQUIRED_VALUE) {
    context.log.warn("Unauthorized request missing or invalid x-custom-auth");
    return new Response(JSON.stringify({ error: "Unauthorized" }), {
      status: 401,
      headers: {
        "content-type": "application/json",
      },
    });
  }

  return request;
}

